import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.BflysNKA.js";const k=JSON.parse('{"title":"常见问题 (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"support/faq.md","filePath":"support/faq.md","lastUpdated":1778577020000}'),l={name:"support/faq.md"};function t(p,s,r,h,d,o){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="常见问题-faq" tabindex="-1">常见问题 (FAQ) <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 (FAQ)&quot;">​</a></h1><p>首次配置可先看 <a href="/beginner/windows">Windows 快速接入</a> 或 <a href="/beginner/macos">macOS 快速接入</a>。</p><h2 id="身份与鉴权-auth" tabindex="-1">身份与鉴权 (Auth) <a class="header-anchor" href="#身份与鉴权-auth" aria-label="Permalink to &quot;身份与鉴权 (Auth)&quot;">​</a></h2><h3 id="为什么我的-key-一直提示无效" tabindex="-1">为什么我的 Key 一直提示无效？ <a class="header-anchor" href="#为什么我的-key-一直提示无效" aria-label="Permalink to &quot;为什么我的 Key 一直提示无效？&quot;">​</a></h3><p>先查最常见的三件事：</p><ul><li>复制时是否带入了前后空格、换行或隐藏字符</li><li>自己写脚本时是否漏掉了 <code>Authorization: Bearer ...</code></li><li>控制台里这把 Key 是否已禁用、余额不足或命中限制</li></ul><p>很多桌面客户端会自动补 <code>Bearer</code>，所以“图形界面能用、自己写 curl 报错”的根因，往往就是 Header 少写了这一层。</p><h3 id="怎么监控我的账单和消耗" tabindex="-1">怎么监控我的账单和消耗？ <a class="header-anchor" href="#怎么监控我的账单和消耗" aria-label="Permalink to &quot;怎么监控我的账单和消耗？&quot;">​</a></h3><p>登录 <a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">小蓝中转站控制台</a>，首页 Dashboard 和<strong>日志</strong>面板可以看到精确到每一条请求的调用记录、Token 消耗和计费明细。</p><p>想把 Claude Code、Codex、Cherry Studio 的消耗分开看，最省事的做法就是给每个工具单独建一把 Key。</p><h2 id="节点与连通性" tabindex="-1">节点与连通性 <a class="header-anchor" href="#节点与连通性" aria-label="Permalink to &quot;节点与连通性&quot;">​</a></h2><h3 id="为什么打开模型广场或控制台一片空白" tabindex="-1">为什么打开模型广场或控制台一片空白？ <a class="header-anchor" href="#为什么打开模型广场或控制台一片空白" aria-label="Permalink to &quot;为什么打开模型广场或控制台一片空白？&quot;">​</a></h3><p>常见原因：</p><ul><li>浏览器插件拦截脚本或请求</li><li>浏览器缓存异常</li><li>当前网络把控制台静态资源拦了</li></ul><p>先关掉广告拦截、脚本拦截类插件，再用无痕窗口重开一次。<br> 如果无痕正常、普通窗口异常，问题大概率就在浏览器缓存或扩展。</p><h3 id="接口端点-endpoint-到底填什么" tabindex="-1">接口端点 (Endpoint) 到底填什么？ <a class="header-anchor" href="#接口端点-endpoint-到底填什么" aria-label="Permalink to &quot;接口端点 (Endpoint) 到底填什么？&quot;">​</a></h3><p>支持 OpenAI 兼容接口的工具，Base URL 一般填：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn/v1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>但不是所有工具都这样。Claude Code 和 Gemini CLI 是两个最容易填错的例外，具体见下面的 <strong>Base URL 要不要加 <code>/v1</code></strong>。</p><h3 id="工具应该去哪里下载" tabindex="-1">工具应该去哪里下载？ <a class="header-anchor" href="#工具应该去哪里下载" aria-label="Permalink to &quot;工具应该去哪里下载？&quot;">​</a></h3><p>优先走官方入口，后面排障最容易对得上。</p><p>常用下载入口：</p><ul><li>Node.js 中文站：<a href="https://nodejs.cn/download" target="_blank" rel="noreferrer">https://nodejs.cn/download</a></li><li>Node.js 镜像归档：<a href="https://npmmirror.com/mirrors/node/" target="_blank" rel="noreferrer">https://npmmirror.com/mirrors/node/</a></li><li>Git for Windows：<a href="https://gitforwindows.org/" target="_blank" rel="noreferrer">https://gitforwindows.org/</a></li><li>Claude Code 官方文档：<a href="https://code.claude.com/docs" target="_blank" rel="noreferrer">https://code.claude.com/docs</a></li><li>Codex CLI 官方文档：<a href="https://developers.openai.com/codex/cli" target="_blank" rel="noreferrer">https://developers.openai.com/codex/cli</a></li><li>Gemini CLI 官方仓库：<a href="https://github.com/google-gemini/gemini-cli" target="_blank" rel="noreferrer">https://github.com/google-gemini/gemini-cli</a></li><li>CC-Switch 中文首页：<a href="https://ccswitch.ai/zh/" target="_blank" rel="noreferrer">https://ccswitch.ai/zh/</a></li><li>Cherry Studio 下载页：<a href="https://docs.cherry-ai.com/cherry-studio/download" target="_blank" rel="noreferrer">https://docs.cherry-ai.com/cherry-studio/download</a></li></ul><p>国内网络环境下第一次装 Node.js，优先看中文站或镜像归档，通常比直接开英文官网更省时间。</p><h2 id="终端与环境变量" tabindex="-1">终端与环境变量 <a class="header-anchor" href="#终端与环境变量" aria-label="Permalink to &quot;终端与环境变量&quot;">​</a></h2><h3 id="npm-install-卡在-idealtree-动不了" tabindex="-1"><code>npm install</code> 卡在 <code>idealTree</code> 动不了？ <a class="header-anchor" href="#npm-install-卡在-idealtree-动不了" aria-label="Permalink to &quot;\`npm install\` 卡在 \`idealTree\` 动不了？&quot;">​</a></h3><p>这类问题多数不是 小蓝中转站 接口故障，而是 npm 下载源太慢或缓存状态不干净。</p><p>先切国内镜像：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>再确认：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出 <code>https://registry.npmmirror.com/</code> 后，再重新执行安装命令。</p><p>如果还是卡住：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 清理 npm 缓存，排除缓存索引异常</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> cache</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> clean</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>然后换一个新终端重试。</p><h3 id="安装-claude-code-前还要装什么" tabindex="-1">安装 Claude Code 前还要装什么？ <a class="header-anchor" href="#安装-claude-code-前还要装什么" aria-label="Permalink to &quot;安装 Claude Code 前还要装什么？&quot;">​</a></h3><p>要先看你走哪条安装路线。</p><p>走 <strong>npm 安装</strong> 时，<code>node</code> 和 <code>npm</code> 就是硬前置：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>走 <strong>原生安装脚本 / Homebrew / WinGet</strong> 时，Node.js 不是 Claude Code 唯一前置；但后面还要继续装 Codex、Gemini CLI、其他 npm CLI 时，提前把 Node.js 和 npm 装好会更省事。</p><p><code>git</code> 则很值得一起准备：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>原因不是“为了多装一个软件”，而是：</p><ul><li>Claude Code、Codex 处理项目时会读取仓库状态、diff 和分支历史</li><li>Windows 上装了 Git for Windows 后，还会附带 Git Bash，很多 Bash 风格命令更顺手</li><li>就算新版本 Claude Code 在 Windows 上没有 Git Bash 也能退回 PowerShell，装好 Git 之后，很多教程和脚本仍然更容易对齐</li></ul><p>Windows 新手直接先把 PowerShell 执行策略、Git、Node.js 跑通，再装 Claude Code 最省事：</p><ol><li><a href="/beginner/windows">Windows 快速接入</a></li><li><a href="/node/windows">Windows Node 安装</a></li></ol><h3 id="claude-code-为什么能装上-但还是走官方登录" tabindex="-1">Claude Code 为什么能装上，但还是走官方登录？ <a class="header-anchor" href="#claude-code-为什么能装上-但还是走官方登录" aria-label="Permalink to &quot;Claude Code 为什么能装上，但还是走官方登录？&quot;">​</a></h3><p>这通常不是“Claude Code 不支持网关”，而是当前终端根本没读到你刚写的变量。</p><p>先检查：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_AUTH_TOKEN</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_MODEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Windows PowerShell：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_AUTH_TOKEN</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_MODEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果这些值在当前窗口里都为空，Claude Code 当然会继续走自己的默认登录流程。</p><h3 id="claude-code-看不到模型列表怎么办" tabindex="-1">Claude Code 看不到模型列表怎么办？ <a class="header-anchor" href="#claude-code-看不到模型列表怎么办" aria-label="Permalink to &quot;Claude Code 看不到模型列表怎么办？&quot;">​</a></h3><p>先确认两层：</p><ol><li>这把 Key 是否真有对应模型权限</li><li>是否已经打开 <code>CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1</code></li></ol><p>Claude Code 官方当前支持在 <code>ANTHROPIC_BASE_URL</code> 指向网关时，请求网关的 <code>/v1/models</code>，把识别到的模型加入 <code>/model</code> 选择器。<br> 这个发现功能不是默认强制开启的，所以你明明接到了网关，也不一定会自动看到所有模型。</p><p>如果模型广场里有、<code>/model</code> 里没有，先直接用完整模型名测试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> 从模型广场复制的模型名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="分组到底怎么选" tabindex="-1">分组到底怎么选？ <a class="header-anchor" href="#分组到底怎么选" aria-label="Permalink to &quot;分组到底怎么选？&quot;">​</a></h3><p>分不清各分组的价格、地区或路由差异时，第一次先选 <code>auto</code> 或默认分组更稳。</p><p>这样做的好处是：</p><ul><li>先把真实链路跑通，不会一上来就被分组限制绊住</li><li>更不容易把“权限不够”误判成“客户端配错”</li><li>后面确认工具都能正常返回后，再按成本和模型类型慢慢收紧</li></ul><p>想把日志、权限和额度拆清楚，给 Claude Code、Codex、Cherry Studio 分别建 Key 会更舒服。</p><h3 id="codex-要怎么装最省事" tabindex="-1">Codex 要怎么装最省事？ <a class="header-anchor" href="#codex-要怎么装最省事" aria-label="Permalink to &quot;Codex 要怎么装最省事？&quot;">​</a></h3><p>常见顺序：</p><ol><li>已经装好 Node.js：直接 <code>npm install -g @openai/codex@latest</code></li><li>常用 Homebrew：<code>brew install --cask codex</code></li><li>不想走包管理器：去官方发布页下载对应系统压缩包</li></ol><p>入口：</p><ul><li>官方文档：<a href="https://developers.openai.com/codex/cli" target="_blank" rel="noreferrer">https://developers.openai.com/codex/cli</a></li><li>官方认证文档：<a href="https://developers.openai.com/codex/auth" target="_blank" rel="noreferrer">https://developers.openai.com/codex/auth</a></li><li>GitHub Release：<a href="https://github.com/openai/codex/releases/latest" target="_blank" rel="noreferrer">https://github.com/openai/codex/releases/latest</a></li></ul><h3 id="gemini-cli-要怎么装最省事" tabindex="-1">Gemini CLI 要怎么装最省事？ <a class="header-anchor" href="#gemini-cli-要怎么装最省事" aria-label="Permalink to &quot;Gemini CLI 要怎么装最省事？&quot;">​</a></h3><p>只想先试一下时，优先：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> @google/gemini-cli</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>准备长期使用时，再装到全局：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> @google/gemini-cli</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>macOS / Linux 常用 Homebrew 时，也可以：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> gemini-cli</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>macOS 还支持 MacPorts：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> port</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> gemini-cli</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>官方入口优先看：</p><ul><li>官方仓库：<a href="https://github.com/google-gemini/gemini-cli" target="_blank" rel="noreferrer">https://github.com/google-gemini/gemini-cli</a></li><li>官方文档目录：<a href="https://github.com/google-gemini/gemini-cli/tree/main/docs" target="_blank" rel="noreferrer">https://github.com/google-gemini/gemini-cli/tree/main/docs</a></li></ul><p>Gemini CLI 版本更新很快。碰到变量名、安装方式或模型选择不一致时，优先回官方仓库和官方文档目录核对。</p><h3 id="改了环境变量-但工具还是不走网关" tabindex="-1">改了环境变量，但工具还是不走网关？ <a class="header-anchor" href="#改了环境变量-但工具还是不走网关" aria-label="Permalink to &quot;改了环境变量，但工具还是不走网关？&quot;">​</a></h3><p>先分两层看：</p><ul><li><strong>终端有没有重读到新变量</strong></li><li><strong>这个工具读的是不是你以为的那组变量</strong></li></ul><p>处理顺序：</p><ul><li><strong>Windows</strong>：完全关闭当前 PowerShell 窗口，再打开一个新窗口</li><li><strong>macOS / Linux</strong>：执行 <code>source ~/.zshrc</code>、<code>source ~/.bashrc</code>，或重开终端</li><li><strong>VSCode 内置终端</strong>：必要时直接重启 VSCode</li></ul><p>再检查：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $OPENAI_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $OPENAI_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $ANTHROPIC_AUTH_TOKEN</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $GOOGLE_GEMINI_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $GEMINI_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> $GEMINI_MODEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>Windows PowerShell：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">OPENAI_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">OPENAI_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ANTHROPIC_AUTH_TOKEN</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">GOOGLE_GEMINI_BASE_URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">GEMINI_API_KEY</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">GEMINI_MODEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>正在用 CC-Switch 时，还要额外留意旧环境变量冲突。CC-Switch 官方当前就把这类冲突列为高频问题：你以为已经切到了新配置，实际终端还在优先读以前手动写进去的旧变量。</p><h3 id="base-url-要不要加-v1" tabindex="-1">Base URL 要不要加 <code>/v1</code>？ <a class="header-anchor" href="#base-url-要不要加-v1" aria-label="Permalink to &quot;Base URL 要不要加 \`/v1\`？&quot;">​</a></h3><p>大多数 OpenAI 兼容工具要加 <code>/v1</code>：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn/v1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>比如：</p><ul><li>Codex</li><li>OpenAI SDK</li><li>各类直接填写 OpenAI Base URL 的脚本和客户端</li></ul><p>但下面这些是例外：</p><p><strong>Claude Code</strong></p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Claude Code 走 Anthropic 协议变量，自己会继续拼 Anthropic 接口路径。这里再手动加 <code>/v1</code>，很容易把地址拼坏。</p><p><strong>Gemini CLI</strong></p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Gemini CLI 当前官方变量是 <code>GOOGLE_GEMINI_BASE_URL</code>，它会自己继续拼接 Gemini API 路径。这里再加 <code>/v1</code>，同样容易错。</p><p><strong>Cherry Studio</strong></p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Cherry Studio 常见填法也是根地址，再由客户端自己补兼容路径。它和很多“直接写 OpenAI Base URL 的工具”不完全一样。</p><h3 id="api-key-要不要带-bearer" tabindex="-1">API Key 要不要带 Bearer？ <a class="header-anchor" href="#api-key-要不要带-bearer" aria-label="Permalink to &quot;API Key 要不要带 Bearer？&quot;">​</a></h3><p>看你在哪儿填。</p><p>图形客户端通常只需要填：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>sk-你的专属Key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>自己写 curl 或代码时，要写完整 Header：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer sk-你的专属Key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="模型名从哪里复制" tabindex="-1">模型名从哪里复制？ <a class="header-anchor" href="#模型名从哪里复制" aria-label="Permalink to &quot;模型名从哪里复制？&quot;">​</a></h3><p>从 <a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a> 复制。</p><p>不要从旧教程、论坛截图、别人的配置片段里抄模型名。最常见的问题不是工具不支持，而是你复制到的是过期模型名。</p><h3 id="cherry-studio-获取不到模型怎么办" tabindex="-1">Cherry Studio 获取不到模型怎么办？ <a class="header-anchor" href="#cherry-studio-获取不到模型怎么办" aria-label="Permalink to &quot;Cherry Studio 获取不到模型怎么办？&quot;">​</a></h3><p>先检查：</p><ol><li>服务商类型是否选成 OpenAI 兼容</li><li>API 地址是否填成 <code>https://xiaolan1.cn</code></li><li>保存后有没有点过 <code>Check</code></li><li>Key 是否有效</li><li>当前 Key 是否有模型权限</li></ol><p>自动获取失败时，直接去模型广场手动复制模型名。</p><h3 id="cc-switch-去哪里下载" tabindex="-1">CC-Switch 去哪里下载？ <a class="header-anchor" href="#cc-switch-去哪里下载" aria-label="Permalink to &quot;CC-Switch 去哪里下载？&quot;">​</a></h3><p>国内用户优先打开：</p><ul><li>中文首页：<a href="https://ccswitch.ai/zh/" target="_blank" rel="noreferrer">https://ccswitch.ai/zh/</a></li><li>官网：<a href="https://ccswitch.ai/" target="_blank" rel="noreferrer">https://ccswitch.ai/</a></li><li>GitHub 发布页：<a href="https://github.com/farion1231/cc-switch/releases" target="_blank" rel="noreferrer">https://github.com/farion1231/cc-switch/releases</a></li></ul><p>Windows 第一次安装优先选 <code>.msi</code>；没有安装权限或只想临时用，再选 <code>Portable.zip</code>。</p><p>macOS 当前官方文档已经明确写了签名和公证，正常情况下可以直接安装打开。</p><h2 id="业务与对公" tabindex="-1">业务与对公 <a class="header-anchor" href="#业务与对公" aria-label="Permalink to &quot;业务与对公&quot;">​</a></h2><h3 id="你们可以开具正规发票吗" tabindex="-1">你们可以开具正规发票吗？ <a class="header-anchor" href="#你们可以开具正规发票吗" aria-label="Permalink to &quot;你们可以开具正规发票吗？&quot;">​</a></h3><p>可以。如果有业务合作、对公转账、开具发票或企业大额采购流程暂不支持，请查看 <a href="/support/after-sales">售前售后</a>。</p>`,127)])])}const u=a(l,[["render",t]]);export{k as __pageData,u as default};
